// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.27;

import {OwnableUpgradeable} from "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";

/// @title SanctionsModule
/// @notice Abstract mixin that manages a sanctions Sparse Merkle Tree root.
/// Used by HederaZetoToken to require non-inclusion proofs on withdraw().
/// The composing contract is responsible for initializing Ownable via the upstream init chain.
abstract contract SanctionsModule is OwnableUpgradeable {
    error NotOwnerOrOracle();
    error SanctionsRootMismatch();

    bytes32 public sanctionsMerkleRoot;
    uint256 public sanctionsMerkleRootBlock;
    address public sanctionsOracle;

    event SanctionsMerkleRootUpdated(bytes32 indexed oldRoot, bytes32 indexed newRoot, uint256 blockNumber);
    event SanctionsOracleSet(address indexed oracle);

    function __SanctionsModule_init() internal onlyInitializing {}

    modifier onlyOwnerOrOracle() {
        if (
            msg.sender != owner() &&
            !(sanctionsOracle != address(0) && msg.sender == sanctionsOracle)
        ) revert NotOwnerOrOracle();
        _;
    }

    function updateSanctionsMerkleRoot(bytes32 newRoot) external onlyOwnerOrOracle {
        bytes32 oldRoot = sanctionsMerkleRoot;
        sanctionsMerkleRoot = newRoot;
        sanctionsMerkleRootBlock = block.number;
        emit SanctionsMerkleRootUpdated(oldRoot, newRoot, block.number);
    }

    function setSanctionsOracle(address oracle) external onlyOwner {
        sanctionsOracle = oracle;
        emit SanctionsOracleSet(oracle);
    }

    function _requireCurrentSanctionsRoot(bytes32 proofSanctionsRoot) internal view {
        if (proofSanctionsRoot != sanctionsMerkleRoot) revert SanctionsRootMismatch();
    }

    uint256[50] private __gap;
}

contracts/hedera/ZetoHTSBridge.sol.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.27;

import {OwnableUpgradeable} from "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import {IHederaTokenService} from "./IHederaTokenService.sol";
import {HederaResponseCodes} from "./HederaResponseCodes.sol";

/// @title ZetoHTSBridge
/// @notice Mixin that manages HTS token association for a Zeto pool contract.
/// HTS tokens must be associated before the contract can hold a balance of them.
/// Inherit alongside the upstream Zeto contract; the composing contract is responsible
/// for initializing Ownable via the upstream init chain (do NOT call __Ownable_init here).
abstract contract ZetoHTSBridge is OwnableUpgradeable {
    error AssociationFailed(int64 responseCode);
    error DissociationFailed(int64 responseCode);
    error TokenNotAssociated(address token);
    error OutstandingShieldedSupply(address token, uint256 amount);

    IHederaTokenService private constant HTS = IHederaTokenService(address(0x167));
    mapping(address => bool) public htsAssociated;
    mapping(address => uint256) public shieldedSupply;

    event HTSTokenAssociated(address indexed token);
    event HTSTokenDissociated(address indexed token);

    /// @dev No-op init; owner is initialized by the composing contract via upstream's
    /// __ZetoCommon_init → __Ownable_init. Present for the `onlyInitializing` discipline.
    function __ZetoHTSBridge_init() internal onlyInitializing {}

    function associateHTSToken(address tokenAddress) external onlyOwner {
        if (!htsAssociated[tokenAddress]) {
            int64 responseCode = HTS.associateToken(address(this), tokenAddress);
            if (
                responseCode != HederaResponseCodes.SUCCESS &&
                responseCode != HederaResponseCodes.TOKEN_ALREADY_ASSOCIATED_TO_ACCOUNT
            ) revert AssociationFailed(responseCode);
            htsAssociated[tokenAddress] = true;
            emit HTSTokenAssociated(tokenAddress);
        }
    }

    function batchAssociateHTSTokens(address[] calldata tokenAddresses) external onlyOwner {
        for (uint256 i = 0; i < tokenAddresses.length; i++) {
            if (!htsAssociated[tokenAddresses[i]]) {
                int64 responseCode = HTS.associateToken(address(this), tokenAddresses[i]);
                if (
                    responseCode != HederaResponseCodes.SUCCESS &&
                    responseCode != HederaResponseCodes.TOKEN_ALREADY_ASSOCIATED_TO_ACCOUNT
                ) revert AssociationFailed(responseCode);
                htsAssociated[tokenAddresses[i]] = true;
                emit HTSTokenAssociated(tokenAddresses[i]);
            }
        }
    }

    function isHTSAssociated(address tokenAddress) external view returns (bool) {
        return htsAssociated[tokenAddress];
    }

    function dissociateHTSToken(address tokenAddress) external onlyOwner {
        if (shieldedSupply[tokenAddress] != 0) {
            revert OutstandingShieldedSupply(tokenAddress, shieldedSupply[tokenAddress]);
        }
        if (htsAssociated[tokenAddress]) {
            int64 responseCode = HTS.dissociateToken(address(this), tokenAddress);
            if (responseCode != HederaResponseCodes.SUCCESS) revert DissociationFailed(responseCode);
            htsAssociated[tokenAddress] = false;
            emit HTSTokenDissociated(tokenAddress);
        }
    }

    function _requireHTSAssociated(address tokenAddress) internal view {
        if (!htsAssociated[tokenAddress]) revert TokenNotAssociated(tokenAddress);
    }

    /// @dev Composing contract calls these to maintain the invariant
    /// (shieldedSupply == sum(deposits) - sum(withdraws)).
    function _incrementShieldedSupply(address token, uint256 amount) internal {
        shieldedSupply[token] += amount;
    }

    function _decrementShieldedSupply(address token, uint256 amount) internal {
        shieldedSupply[token] -= amount;
    }

    uint256[50] private __gap;
}

contracts/hedera/ZetoVkeySetter.sol.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.27;

import {OwnableUpgradeable} from "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import {UUPSUpgradeable} from "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";

/// @dev Minimal interface for the Groth16 verifier registry.
interface IZetoVerifierRegistry {
    struct G1Point { uint256 x; uint256 y; }
    struct G2Point { uint256[2] x; uint256[2] y; }
    struct VerifyingKey {
        G1Point alpha1;
        G2Point beta2;
        G2Point gamma2;
        G2Point delta2;
        G1Point[] ic;
    }
    function setVerifyingKey(bytes32 circuitId, VerifyingKey calldata vk) external;
}

/// @title ZetoVkeySetter
/// @notice Owner-only verifying key management for Zeto circuits on Hedera.
/// UUPS-upgradeable until lock() is called; after lock, vkeys cannot change.
contract ZetoVkeySetter is OwnableUpgradeable, UUPSUpgradeable {
    error VkeysLocked();
    error NoStagedKey(bytes32 circuitId);
    error ArrayLengthMismatch();
    error MissingCircuit(bytes32 circuitId);
    error EmptyExpectedCircuits();

    IZetoVerifierRegistry public verifierRegistry;
    bool public locked;
    mapping(bytes32 => IZetoVerifierRegistry.VerifyingKey) private stagedKeys;
    mapping(bytes32 => bool) public hasStaged;
    mapping(bytes32 => bool) public isCommitted;
    bytes32[] public expectedCircuits;

    event VerifyingKeyStaged(bytes32 indexed circuitId, string circuitName);
    event VerifyingKeyCommitted(bytes32 indexed circuitId, string circuitName);
    event VKeySetLocked();

    modifier onlyUnlocked() {
        if (locked) revert VkeysLocked();
        _;
    }

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() { _disableInitializers(); }

    /// @param expectedCircuits_ keccak256 circuit IDs that MUST be committed before
    /// lock() succeeds. Set once; cannot be modified after initialize.
    function initialize(
        address initialOwner,
        address _verifierRegistry,
        bytes32[] calldata expectedCircuits_
    ) external initializer {
        if (expectedCircuits_.length == 0) revert EmptyExpectedCircuits();
        __Ownable_init(initialOwner);
        verifierRegistry = IZetoVerifierRegistry(_verifierRegistry);
        for (uint256 i = 0; i < expectedCircuits_.length; i++) {
            expectedCircuits.push(expectedCircuits_[i]);
        }
    }

    function _authorizeUpgrade(address) internal override onlyOwner {}

    function stageVerifyingKey(
        string calldata circuitName,
        IZetoVerifierRegistry.VerifyingKey calldata vk
    ) external onlyOwner onlyUnlocked {
        bytes32 circuitId = keccak256(bytes(circuitName));
        stagedKeys[circuitId] = vk;
        hasStaged[circuitId] = true;
        emit VerifyingKeyStaged(circuitId, circuitName);
    }

    function batchStageVerifyingKeys(
        string[] calldata circuitNames,
        IZetoVerifierRegistry.VerifyingKey[] calldata vks
    ) external onlyOwner onlyUnlocked {
        if (circuitNames.length != vks.length) revert ArrayLengthMismatch();
        for (uint256 i = 0; i < circuitNames.length; i++) {
            bytes32 circuitId = keccak256(bytes(circuitNames[i]));
            stagedKeys[circuitId] = vks[i];
            hasStaged[circuitId] = true;
            emit VerifyingKeyStaged(circuitId, circuitNames[i]);
        }
    }

    function commitVerifyingKey(string calldata circuitName) external onlyOwner onlyUnlocked {
        bytes32 circuitId = keccak256(bytes(circuitName));
        if (!hasStaged[circuitId]) revert NoStagedKey(circuitId);
        verifierRegistry.setVerifyingKey(circuitId, stagedKeys[circuitId]);
        isCommitted[circuitId] = true;
        emit VerifyingKeyCommitted(circuitId, circuitName);
    }

    function batchCommitVerifyingKeys(string[] calldata circuitNames) external onlyOwner onlyUnlocked {
        for (uint256 i = 0; i < circuitNames.length; i++) {
            bytes32 circuitId = keccak256(bytes(circuitNames[i]));
            if (!hasStaged[circuitId]) revert NoStagedKey(circuitId);
            verifierRegistry.setVerifyingKey(circuitId, stagedKeys[circuitId]);
            isCommitted[circuitId] = true;
            emit VerifyingKeyCommitted(circuitId, circuitNames[i]);
        }
    }

    /// @notice Permanently lock the vkey set. Reverts unless every circuit in
    /// `expectedCircuits` has been committed via commitVerifyingKey(). Irreversible.
    function lock() external onlyOwner {
        for (uint256 i = 0; i < expectedCircuits.length; i++) {
            if (!isCommitted[expectedCircuits[i]]) revert MissingCircuit(expectedCircuits[i]);
        }
        locked = true;
        emit VKeySetLocked();
    }

    /// @notice True if all expected circuits are committed and lock() would succeed.
    function readyToLock() external view returns (bool) {
        for (uint256 i = 0; i < expectedCircuits.length; i++) {
            if (!isCommitted[expectedCircuits[i]]) return false;
        }
        return true;
    }

    /// @notice Return the subset of expected circuits that have not yet been committed.
    function uncommittedCircuits() external view returns (bytes32[] memory) {
        uint256 n;
        for (uint256 i = 0; i < expectedCircuits.length; i++) {
            if (!isCommitted[expectedCircuits[i]]) n++;
        }
        bytes32[] memory out = new bytes32[](n);
        uint256 k;
        for (uint256 i = 0; i < expectedCircuits.length; i++) {
            if (!isCommitted[expectedCircuits[i]]) {
                out[k++] = expectedCircuits[i];
            }
        }
        return out;
    }

    function expectedCircuitsCount() external view returns (uint256) {
        return expectedCircuits.length;
    }

    uint256[50] private __gap;
}

